},function (){var _vm=this,_c=_vm._self._c,_setup=_vm._self._setupProxy;return _c('div',{staticClass:"fvl_about"},[_c('div',{staticClass:"about_fvl"},[_c('p',[_vm._v("自2020年起，C-LAB 未來視覺實驗室持續推動實驗展演計畫「FUTURE VISION LAB」， 遂以數位實驗建築著手打造穹形場域（DOME），以探索科技媒體的視覺極限為目標，過去四年已進行百餘件作品展演。 於2023年在文化部支持下，開啟軟硬體升級計畫，尺寸突破過往尺度， 打造直徑15公尺、全臺唯一巨型移動式戶外沉浸式體驗空間「C-LAB穹頂劇場」。 影音軟硬體歷經數次迭代開發，克服球形曲面投影的校正、融接、對位、播放控制與影像前製等多重技術之複雜度， 沉浸影像投影系統總運算可達 8K*8K超高解析度；內部以雙層結構隱藏影音設備， 客製新型態透聲投影膜片並與臺灣聲響實驗室攜手合作建構更完善的25.4聲道環繞聲場環境。 未來視覺實驗室逐年針對穹形沉浸式場域打造接軌國際規格的創作環境，不僅展現臺灣高量能的創造力， 也讓觀眾享受更高品質的沉浸式感官內容與體驗。")]),_c('p',[_vm._v("今年度「FUTURE VISION LAB 2024」， 於11月1日起至12月22日，連續8個周末， 展映來自德國、波士尼亞與赫塞哥維納、澳洲、日本、韓國、中國及臺灣等各國精彩作品， 共計15檔節目和3場推廣講座及工作坊；同時未來視覺實驗室積極與國內外單位串聯與合作，呈現展覽、播映和現場Live 演出等不同形式， 一次掌握穹頂場域最新的創作內容，與創作者們一起潛入沉浸式作品帶來的感官體驗之中。")])])])
